/**
 * NmiTheme - A comprehensive, nested theme structure for styling NmiPayments components
 */
export interface NmiLayoutTheme {
    radius: {
        small: string;
        medium: string;
        large: string;
    };
    borderWidth: {
        small: string;
        medium: string;
        large: string;
    };
    spacing: {
        padding: string;
        xs: string;
        sm: string;
        md: string;
        lg: string;
        xl: string;
        '2xl': string;
        '3xl': string;
    };
}
export interface NmiTypographyTheme {
    size: {
        xs: string;
        sm: string;
        md: string;
        lg: string;
        xl: string;
        '2xl': string;
    };
    weight: {
        light: string;
        medium: string;
        bold: string;
    };
    font: {
        sans: string;
        mono: string;
    };
}
export interface NmiColorPair {
    default: string;
    foreground: string;
}
export interface NmiColorScale extends NmiColorPair {
    100: string;
    200: string;
}
export interface NmiSemanticColors {
    primary: NmiColorScale;
    secondary: NmiColorScale;
    success: NmiColorScale;
    warning: NmiColorScale;
    danger: NmiColorScale;
    default: NmiColorScale;
}
export interface NmiContentColors {
    content1: NmiColorScale;
    content2: NmiColorScale;
}
export interface NmiColorsTheme extends NmiSemanticColors, NmiContentColors {
    background: string;
    foreground: string;
    border: string;
    input: string;
}
export interface NmiTheme {
    layout: NmiLayoutTheme;
    typography: NmiTypographyTheme;
    colors: NmiColorsTheme;
}
export interface Appearance {
    theme?: 'light' | 'dark';
    customTheme?: Partial<NmiTheme>;
    layoutSpacing?: 'compact' | 'default' | 'spacious';
    textSize?: 'smaller' | 'default' | 'larger';
    radiusSize?: 'none' | 'smaller' | 'default' | 'larger';
}
